parameters.jsCode:
// Grab all incoming items from the API node
const items = $input.all();

let selectedTitle = "";
let selectedContext = "";

// 1. Check if it's Hacker News data (wrapped in a single item with a 'hits' array)
if (items[0].json.hits && Array.isArray(items[0].json.hits)) {
  const hits = items[0].json.hits;
  const randomHit = hits[Math.floor(Math.random() * hits.length)];
  selectedTitle = randomHit.title;
  selectedContext = "Tech startup and engineering trends";
} 
// 2. Otherwise, it's Dev.to data (split into multiple separate items)
else {
  const randomItem = items[Math.floor(Math.random() * items.length)];
  selectedTitle = randomItem.json.title;
  selectedContext = randomItem.json.description || "Web development trends";
}

// Force n8n to output exactly ONE clean item
return [{
  json: {
    title: selectedTitle,
    context: selectedContext
  }
}];

// 1. Grab the single random trend we picked upstream
const trend = $('Pick One Trend').item.json;

// 2. Grab all historical rows returned from your Read History node
const historyItems = $input.all();

// 3. Sort by date descending (newest first) and grab only the top 5 rows
// NOTE: This assumes your Google Sheet columns are named exactly "Date" and "Post Text"
const latestFive = historyItems
  .map(item => item.json)
  .filter(row => row.Date) // Drops any empty rows to prevent crashes
  .sort((a, b) => new Date(b.Date) - new Date(a.Date))
  .slice(0, 5);

// 4. Extract the post text and format it into a clean markdown bulleted list
const pastPostsText = latestFive
  .map(row => row['Post Text'] || '')
  .filter(text => text.trim() !== '')
  .map(text => `- ${text}`)
  .join('\n');

// 5. Output exactly ONE clean item to choke n8n's looping engine and feed Gemini
return [{
  json: {
    title: trend.title,
    context: trend.context,
    history: pastPostsText || "No previous posts recorded yet."
  }
}];
